1	// One-off ops tool: re-evaluate a single uploaded document through the
2	// document-ingestion pipeline with a clean slate.
3	//
4	// WHY: ingestion is idempotent only by content/candidate hash. Re-running after
5	// a chunking/prompt change therefore ADDS new claims beside the old ones instead
6	// of replacing them. This script removes a document's prior extraction artifacts
7	// (claims, evidence, chunks, candidates, batches, domain tags) and resets the
8	// document to `pending_processing` so the worker re-extracts it from scratch.
9	//
10	// SAFETY:
11	//   - DRY-RUN by default. It only deletes when APPLY=1 is set.
12	//   - It REFUSES to proceed if any target claim is (a) cited in the Brain
13	//     (section_claims), (b) part of a contradiction, (c) referenced by a gap, or
14	//     (d) multi-source (has evidence from other documents/messages). Those cases
15	//     need manual handling (supersede via /admin/claims), not deletion.
16	//   - All deletes run inside ONE transaction.
17	//
18	// USAGE (PowerShell):
19	//   $env:PROD_URL = "<session-pooler connection string>"
20	//   $env:DOCUMENT_ID = "9d09fa89-3a46-465e-a98b-837287c9e22a"
21	//   node scripts/reevaluate-document.mjs           # dry run — prints the plan
22	//   $env:APPLY = "1"; node scripts/reevaluate-document.mjs   # actually do it
23	//
24	// AFTER APPLY: trigger the `document-ingestion` task for DOCUMENT_ID (or wait for
25	// the document-ingestion-sweep cron). The NEW worker code must be deployed first,
26	// otherwise you just re-run the old logic.
27	
28	import postgres from 'postgres';
29	
30	const url = process.env.PROD_URL || process.env.DIRECT_URL || process.env.DATABASE_URL;
31	const docId = process.env.DOCUMENT_ID;
32	const APPLY = process.env.APPLY === '1';
33	
34	if (!url) throw new Error('Set PROD_URL (or DIRECT_URL/DATABASE_URL).');
35	if (!docId) throw new Error('Set DOCUMENT_ID.');
36	
37	const sql = postgres(url, { max: 1, prepare: false, connect_timeout: 30 });
38	
39	function log(...a) {
40	  console.log(...a);
41	}
42	
43	try {
44	  const [doc] = await sql`select id, file_name, status from documents where id = ${docId}`;
45	  if (!doc) throw new Error(`document ${docId} not found`);
46	  log(`Document: ${doc.file_name} (${doc.id}) — status=${doc.status}`);
47	
48	  const chunkIds = (
49	    await sql`select id from document_chunks where document_id = ${docId}`
50	  ).map((r) => r.id);
51	  const claimIds = (
52	    await sql`select distinct ce.claim_id from claim_evidence ce
53	              join document_chunks dc on dc.id = ce.source_document_chunk_id
54	              where dc.document_id = ${docId} and ce.claim_id is not null`
55	  ).map((r) => r.claim_id);
56	  const candidateIds = (
57	    await sql`select distinct cce.candidate_id from extraction_candidate_evidence cce
58	              join document_chunks dc on dc.id = cce.source_document_chunk_id
59	              where dc.document_id = ${docId} and cce.candidate_id is not null`
60	  ).map((r) => r.candidate_id);
61	  const batchIds = (
62	    await sql`select distinct eb.id from extraction_batches eb
63	              join job_runs jr on jr.id = eb.job_run_id
64	              where jr.input_json->>'documentId' = ${docId}`
65	  ).map((r) => r.id);
66	
67	  log(
68	    `Scope: ${chunkIds.length} chunks, ${claimIds.length} claims, ` +
69	      `${candidateIds.length} candidates, ${batchIds.length} batches`,
70	  );
71	
72	  // ── Safety guards ──────────────────────────────────────────────────────
73	  const guard = async (label, q) => {
74	    if (claimIds.length === 0) return 0;
75	    const [{ n }] = await q;
76	    const num = Number(n);
77	    if (num > 0) log(`  ⚠ BLOCKER — ${label}: ${num}`);
78	    return num;
79	  };
80	  let blockers = 0;
81	  blockers += await guard(
82	    'claims also have evidence from OTHER sources (multi-source)',
83	    sql`select count(*) n from (
84	          select ce.claim_id from claim_evidence ce
85	          left join document_chunks dc on dc.id = ce.source_document_chunk_id
86	          where ce.claim_id = any(${claimIds})
87	          group by ce.claim_id
88	          having bool_or(dc.document_id is distinct from ${docId} or ce.source_document_chunk_id is null)
89	        ) x`,
90	  );
91	  blockers += await guard(
92	    'claims cited in the Brain (section_claims)',
93	    sql`select count(*) n from section_claims where claim_id = any(${claimIds})`,
94	  );
95	  blockers += await guard(
96	    'claims in contradictions',
97	    sql`select count(*) n from contradictions
98	        where claim_a_id = any(${claimIds}) or claim_b_id = any(${claimIds}) or resolved_by_claim_id = any(${claimIds})`,
99	  );
100	  blockers += await guard(
101	    'claims referenced by gaps',
102	    sql`select count(*) n from gaps g
103	        where g.resolved_by_claim_id = any(${claimIds})
104	           or exists (select 1 from jsonb_array_elements_text(g.related_claim_ids) x(v) where x.v = any(${claimIds}))`,
105	  );
106	
107	  if (blockers > 0) {
108	    log(`\nABORTING: ${blockers} provenance blocker(s). Handle these claims via /admin/claims (supersede/reject) first.`);
109	    await sql.end();
110	    process.exit(1);
111	  }
112	  log('  ✓ no provenance blockers (safe to delete)');
113	
114	  if (!APPLY) {
115	    log('\nDRY RUN — nothing deleted. Re-run with APPLY=1 (after deploying the new worker) to execute.');
116	    log('Then trigger `document-ingestion` for this DOCUMENT_ID.');
117	    await sql.end();
118	    process.exit(0);
119	  }
120	
121	  // ── Apply (single transaction) ─────────────────────────────────────────
122	  const deleted = {};
123	  await sql.begin(async (tx) => {
124	    const del = async (key, q) => {
125	      const r = await q;
126	      deleted[key] = r.count ?? 0;
127	    };
128	    // Delete extraction artifacts FIRST so candidate→claim back-pointers
129	    // (promoted_to_claim_id / duplicate_of_claim_id) disappear by row deletion.
130	    // Nulling them in place would violate extraction_candidates' promoted/
131	    // duplicate consistency CHECK; deleting the row does not.
132	    if (candidateIds.length) {
133	      await del('extraction_validation_results', tx`delete from extraction_validation_results where candidate_id = any(${candidateIds})`);
134	      await del('extraction_candidate_evidence', tx`delete from extraction_candidate_evidence where candidate_id = any(${candidateIds})`);
135	      await del('extraction_candidates', tx`delete from extraction_candidates where id = any(${candidateIds})`);
136	    }
137	    if (claimIds.length) {
138	      // Safety net: any stray candidate (outside candidateIds) still pointing at
139	      // a target claim — delete it too, so the claim delete can't hit an FK.
140	      await tx`delete from extraction_candidates where promoted_to_claim_id = any(${claimIds}) or duplicate_of_claim_id = any(${claimIds})`;
141	      await del('claim_review_events', tx`delete from claim_review_events where claim_id = any(${claimIds}) or replacement_claim_id = any(${claimIds})`);
142	      await del('claim_domains', tx`delete from claim_domains where claim_id = any(${claimIds})`);
143	      await del('claim_entities', tx`delete from claim_entities where claim_id = any(${claimIds})`);
144	      await del('claim_top_domains', tx`delete from claim_top_domains where claim_id = any(${claimIds})`);
145	      await del('claim_sub_topics', tx`delete from claim_sub_topics where claim_id = any(${claimIds})`);
146	      await del('claim_translations', tx`delete from claim_translations where claim_id = any(${claimIds})`);
147	      // NOTE: employee_claims is a VIEW (not a base table), so it is not deleted here.
148	      await del('claim_metadata', tx`delete from claim_metadata where claim_id = any(${claimIds})`);
149	      await del('claim_evidence', tx`delete from claim_evidence where claim_id = any(${claimIds})`);
150	      await del('claims', tx`delete from claims where id = any(${claimIds})`);
151	    }
152	    if (batchIds.length) {
153	      // Only batches with no surviving candidates (all were doc-scoped).
154	      await del('extraction_batches', tx`delete from extraction_batches eb where eb.id = any(${batchIds})
155	        and not exists (select 1 from extraction_candidates c where c.extraction_batch_id = eb.id)`);
156	    }
157	    if (chunkIds.length) {
158	      await del('document_chunk_top_domains', tx`delete from document_chunk_top_domains where document_chunk_id = any(${chunkIds})`);
159	      await del('document_chunk_entities', tx`delete from document_chunk_entities where document_chunk_id = any(${chunkIds})`);
160	      // Belt-and-suspenders: any extraction evidence still pointing at these chunks.
161	      await tx`delete from extraction_candidate_evidence where source_document_chunk_id = any(${chunkIds})`;
162	    }
163	    await del('document_chunks', tx`delete from document_chunks where document_id = ${docId}`);
164	    await del('document_top_domains', tx`delete from document_top_domains where document_id = ${docId}`);
165	    await tx`update documents set status = 'pending_processing', processed_at = null, processing_error = null where id = ${docId}`;
166	  });
167	
168	  log('\nDELETED:');
169	  for (const [k, v] of Object.entries(deleted)) log(`  ${k}: ${v}`);
170	  log(`\nDocument reset to pending_processing. Now trigger the document-ingestion task for ${docId}.`);
171	} finally {
172	  await sql.end();
173	}
