import postgres from 'postgres';
const sql = postgres(process.env.PROD_URL, { max:1, prepare:false, connect_timeout:25 });
const ext = process.env.SET_EXT;   // extraction route id, raw e.g. openai/gpt-4o-mini
const vis = process.env.SET_VIS;   // vision route id, raw
const pool = process.env.SET_POOL; // JSON array string for model_pool_extraction
if (ext) await sql`update settings set value=${sql.json(ext)} where key='default_extraction_route'`;
if (vis) await sql`update settings set value=${sql.json(vis)} where key='default_vision_route'`;
if (pool) await sql`update settings set value=${sql.json(JSON.parse(pool))} where key='model_pool_extraction'`;
const rows = await sql`select key, value from settings where key in ('default_extraction_route','default_vision_route','model_pool_extraction')`;
for (const r of rows) console.log('VERIFY', r.key, '=', JSON.stringify(r.value));
await sql.end();

