const sql = postgres(process.env.PROD_URL, { max:1, prepare:false, connect_timeout:25 });
const D = '9d09fa89-3a46-465e-a98b-837287c9e22a';
const [d] = await sql`select status, processing_error, processed_at from documents where id=${D}`;
const [c] = await sql`select count(distinct c.id)::int n from claims c join claim_evidence ce on ce.claim_id=c.id
  join document_chunks dc on dc.id=ce.source_document_chunk_id where dc.document_id=${D}`;
console.log(JSON.stringify({status:d.status, err:d.processing_error, processed_at:d.processed_at, claims:c.n}));
await sql.end();

import postgres from 'postgres';
const sql = postgres(process.env.PROD_URL, { max:1, prepare:false, connect_timeout:25 });
const D = '9d09fa89-3a46-465e-a98b-837287c9e22a';
const LABEL = process.env.LABEL || 'run';

// pricing map
const price = {
  'openai/gpt-4o-mini':[0.15,0.60],
  'openai/gpt-4.1-mini':[0.40,1.60],
  'google/gemini-2.5-flash':[0.30,2.50],
  'google/gemini-3.1-flash-lite':[0.25,1.50],
  'qwen/qwen3-vl-235b-a22b-thinking':[0.26,2.60],
};

console.log(`\n##### COLLECT ${LABEL} #####`);

// model_runs for most recent ingestion + vision
const runs = await sql`select task_type,provider,model,success,error,input_tokens,output_tokens,cost_usd,latency_ms,created_at
  from model_runs where task_type ilike 'document-ingestion%' order by created_at desc limit 4`;
console.log('--- model_runs (recent) ---');
for (const r of runs) {
  const key = r.provider+'/'+r.model;
  const p = price[key];
  const cost = p ? (r.input_tokens*p[0]+r.output_tokens*p[1])/1e6 : null;
  console.log(JSON.stringify({task:r.task_type, route:key, success:r.success, err:r.error, in:r.input_tokens, out:r.output_tokens, lat_s:(r.latency_ms/1000).toFixed(1), cost_usd: cost?cost.toFixed(6):null, at:r.created_at}));
}

// attempts
console.log('--- model_run_attempts (recent 8) ---');
const att = await sql`select task_type, slot, attempt_index, route_id, provider, model_id, is_primary, status, error, created_at
  from model_run_attempts order by created_at desc limit 8`;
for (const a of att) console.log(JSON.stringify({task:a.task_type, slot:a.slot, idx:a.attempt_index, route:a.route_id, model:a.model_id, primary:a.is_primary, status:a.status, err:a.error}));

// transcription stats
