   jsonb_array_length(coalesce(eb.raw_model_output->'claims','[]'::jsonb)) returned, eb.validation_summary
  from extraction_batches eb join job_runs jr on jr.id=eb.job_run_id
  where jr.input_json->>'documentId'=${D} order by eb.created_at desc`;
